method PartitionBellNumbers(n: int) returns (ways: int)
  requires n >= 0
  ensures ways == BellNumber(n)
{
  var B := new int[n + 1];
  B[0] := 1;

  var i := 1;
  while i <= n
    invariant 1 <= i <= n + 1
    invariant forall j :: 0 <= j < i ==> B[j] == BellNumber(j)
    decreases n - i
  {
    var sumA := 0;
    var sumB := 0;
    var k := 0;

    while k <= i - 1
      invariant 0 <= k <= i
      invariant sumB == BellPrefix(i, k)
      invariant sumA == sumB
      decreases i - 1 - k
    {
      assert 0 <= k < i;                 
      assert B[k] == BellNumber(k);     

      var c := BinomialCoefficient(i - 1, k);
      sumA := sumA + c * B[k];
      sumB := sumB + c * BellNumber(k);
      k := k + 1;
    }

    // 结束时：k == i，因此 sumB == BellPrefix(i,i) == BellNumber(i)
    assert sumB == BellPrefix(i, i);
    assert sumB == BellNumber(i);
    assert sumA == sumB;                 

    B[i] := sumA;
    i := i + 1;
  }

  ways := B[n];
}


function BinomialCoefficient(a: int, b: int): int
  requires 0 <= b <= a
  decreases a, b
{
  if b == 0 || b == a then 1
  else BinomialCoefficient(a - 1, b - 1) + BinomialCoefficient(a - 1, b)
}

// Bell 的前缀和：BellPrefix(i,k) = Σ_{m=0}^{k-1} C(i-1,m) * BellNumber(m)
function BellPrefix(i: int, k: int): int
  requires 0 <= k <= i
  decreases i, 0, k
{
  if k == 0 then 0
  else BellPrefix(i, k - 1) + BinomialCoefficient(i - 1, k - 1) * BellNumber(k - 1)
}

function BellNumber(k: int): int
  requires k >= 0
  decreases k, 0
{
  if k == 0 then 1 else BellPrefix(k, k)
}
